const V={bg:"#e8ecf1",bd:"#d1d9e2",mt:"#64748b",dk:"#0f172a",pr:"#1e3a5f",pl:"#e8f0f6",sb:"#1e293b",shadow:"0 4px 24px rgba(15,23,42,.06)",shadowLg:"0 12px 48px rgba(15,23,42,.08)"};
const CSS=`@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+JP:wght@400;500;600;700;800;900&family=Shippori+Mincho:wght@500;600;700&display=swap');*{margin:0;padding:0;box-sizing:border-box}html{overflow-x:hidden}body{font-family:'Noto Sans JP',sans-serif;background:${V.bg};color:${V.dk};-webkit-font-smoothing:antialiased;font-size:16px;overflow-x:hidden}::-webkit-scrollbar{width:6px}::-webkit-scrollbar-thumb{background:#94a3b8;border-radius:3px}@keyframes fu{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:none}}@keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}.fu{animation:fu .5s ease-out both}input:focus,textarea:focus,select:focus{border-color:${V.pr}!important;box-shadow:0 0 0 3px rgba(30,58,95,.1)}button{font-family:inherit;min-height:44px;min-width:44px}textarea{font-family:inherit}.lp-sec-label{font-size:11px;font-weight:700;letter-spacing:.2em;color:${V.pr};text-transform:uppercase;margin-bottom:10px}.lp-h2{font-size:clamp(22px,4.5vw,38px);font-weight:900;letter-spacing:-.02em;line-height:1.25}
@media(max-width:768px){.lp-header{height:56px!important;padding:0 12px!important}.lp-header .lp-nav-wrap{display:none}.lp-menu-backdrop{display:none;position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:99;backdrop-filter:blur(2px)}.lp-header.lp-menu-open .lp-menu-backdrop{display:block}.lp-header.lp-menu-open .lp-nav-wrap{display:flex;flex-direction:column;position:fixed;top:0;right:0;bottom:0;width:min(300px,88vw);max-width:100%;background:rgba(7,26,44,.99);backdrop-filter:blur(12px);padding:56px 0 24px;gap:0;border-left:1px solid rgba(255,255,255,.1);box-shadow:-8px 0 24px rgba(0,0,0,.3);z-index:101;overflow-y:auto;animation:lp-drawer .25s ease-out}.lp-header .lp-nav-wrap .lp-nav-link{width:100%;justify-content:flex-start;padding:16px 20px;font-size:15px;min-height:48px;border-radius:0;border-bottom:1px solid rgba(255,255,255,.06)}.lp-header .lp-nav-wrap .lp-actions{margin:12px 16px 0;padding-top:12px;border-top:1px solid rgba(255,255,255,.15);flex-direction:column;gap:8px}.lp-header .lp-nav-wrap .lp-actions button{width:100%;padding:14px 18px;font-size:14px;min-height:48px;justify-content:center}.lp-hamburger{display:flex!important;align-items:center;justify-content:center;background:transparent;border:none;color:#fff;cursor:pointer;padding:10px;min-width:48px;min-height:48px;border-radius:8px}.lp-hamburger:active{background:rgba(255,255,255,.1)}@keyframes lp-drawer{from{transform:translateX(100%);opacity:.9}to{transform:translateX(0);opacity:1}}.lp-hero{padding:72px 16px 48px!important;min-height:100vh;min-height:100dvh}.lp-hero h1{font-size:clamp(22px,7vw,56px)!important;margin-bottom:14px!important}.lp-hero .lp-hero-lead{font-size:14px!important;margin-bottom:24px!important}.lp-hero .lp-hero-btns{flex-direction:column;width:100%;gap:10px}.lp-hero .lp-hero-btns button{width:100%;padding:14px 20px;font-size:15px}.lp-section{padding:48px 16px!important}.lp-section .lp-inner{max-width:100%!important;padding:0 4px}.lp-contact{padding:56px 16px!important}.lp-contact .lp-cta-btns{flex-direction:column;gap:10px}.lp-contact .lp-cta-btns button{width:100%;padding:14px 20px}.lp-scroll-top{bottom:20px!important;right:16px!important;width:48px!important;height:48px!important}}
@media(min-width:769px){.lp-hamburger{display:none!important}}`;
const initU=[{id:"a1",email:"admin@keikaku.jp",pw:"admin123",name:"\u7ba1\u7406\u8005",role:"admin",ok:true,region:null,affCode:"ADMIN001",refs:0,comm:0,perms:{innovation:1,subsidy:1,report:1,other:1},fd:{}},{id:"u1",email:"demo@example.com",pw:"demo123",name:"\u30c7\u30e2\u4f01\u696d\uff08\u6771\u4eac\uff09",role:"member",ok:true,region:"tokyo",affCode:"DEMO0001",refs:3,comm:4500,perms:{innovation:1,subsidy:1,report:0,other:0},fd:{}}];

const profileToUser=(p)=>({id:p.id,email:p.email,pw:"",name:p.name,role:p.role||"member",ok:!!p.ok,region:p.region,affCode:p.aff_code||"",refs:p.refs||0,comm:p.comm||0,perms:p.perms||{innovation:0,subsidy:0,report:0,other:0},fd:p.fd||{}});

/* APP */
export default function App(){
  const[user,setUser]=useState(null);const[page,setPage]=useState("landing");const[users,setUsers]=useState(initU);
  const nav=useCallback(p=>{setPage(p);window.scrollTo(0,0);},[]);
  useEffect(()=>{
    if(!hasSupabase())return;
    supabase.auth.getSession().then(({data:{session}})=>{
      if(!session)return;
      supabase.from("profiles").select("*").eq("id",session.user.id).single().then(({data:p})=>{if(p)setUser(profileToUser(p));});
    });
    const {data:{subscription}}=supabase.auth.onAuthStateChange((_e,session)=>{
      if(!session){setUser(null);return;}
      supabase.from("profiles").select("*").eq("id",session.user.id).single().then(({data:p})=>{if(p)setUser(profileToUser(p));});
    });
    return ()=>{subscription?.unsubscribe?.();};
  },[]);
  useEffect(()=>{
    if(!hasSupabase()||!user||user.role!=="admin")return;
    supabase.from("profiles").select("*").then(({data:rows})=>{if(rows?.length)setUsers(rows.map(profileToUser));});
  },[user?.id,user?.role]);
  const sendWelcomeEmail=(to,name)=>{fetch("/api/send-email",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({to,subject:"【経営革新AIアシスト】ご登録ありがとうございます",html:`<p>${name} 様</p><p>ご登録いただきありがとうございます。管理者の承認後、ログインしてご利用いただけます。</p><p>— 経営革新 AI アシスト</p>`})}).catch(()=>{});};
  const login=useCallback(async(em,pw)=>{
    if(hasSupabase()){
      const {data,error}=await supabase.auth.signInWithPassword({email:em,password:pw});
      if(error)return error.message==="Invalid login credentials"?"\u8a8d\u8a3c\u30a8\u30e9\u30fc":"\u30a8\u30e9\u30fc";
      const {data:p}=await supabase.from("profiles").select("*").eq("id",data.user.id).single();
      if(!p)return"\u30a8\u30e9\u30fc";if(!p.ok)return"\u627f\u8a8d\u5f85\u3061";setUser(profileToUser(p));nav(p.role==="admin"?"admin":"member");return null;
    }
    const u=users.find(x=>x.email===em&&x.pw===pw);if(!u)return"\u8a8d\u8a3c\u30a8\u30e9\u30fc";if(!u.ok)return"\u627f\u8a8d\u5f85\u3061";setUser(u);nav(u.role==="admin"?"admin":"member");return null;
  },[users]);
  const register=useCallback(async(em,pw,nm,rg,ref)=>{
    if(users.find(u=>u.email===em))return"\u767b\u9332\u6e08\u307f";
    if(hasSupabase()){
      const {data,error}=await supabase.auth.signUp({email:em,password:pw,options:{data:{name:nm,region:rg}}});
      if(error)return error.message.includes("already")?"\u767b\u9332\u6e08\u307f":error.message;
      const uid=data.user?.id;if(!uid)return"\u30a8\u30e9\u30fc";
      const ac=nm.replace(/[^a-zA-Z0-9]/g,"").slice(0,4).toUpperCase().padEnd(4,"X")+String(uid).slice(0,4);
      const ins={id:uid,email:em,name:nm,role:"member",ok:false,region:rg,aff_code:ac,refs:0,comm:0,perms:{innovation:0,subsidy:0,report:0,other:0},fd:{}};
      await supabase.from("profiles").insert(ins);
      if(ref){const {data:refRow}=await supabase.from("profiles").select("id,refs,comm").eq("aff_code",ref).single();if(refRow)await supabase.from("profiles").update({refs:(refRow.refs||0)+1,comm:(refRow.comm||0)+1500}).eq("id",refRow.id);}
      sendWelcomeEmail(em,nm);return null;
    }
    const ac=nm.replace(/[^a-zA-Z0-9]/g,"").slice(0,4).toUpperCase().padEnd(4,"X")+String(users.length).padStart(4,"0");const nu={id:Math.random().toString(36).substr(2,8),email:em,pw,name:nm,role:"member",ok:false,region:rg,affCode:ac,refs:0,comm:0,perms:{innovation:0,subsidy:0,report:0,other:0},fd:{}};setUsers(p=>{const up=[...p,nu];if(ref){const r=up.find(u=>u.affCode===ref);if(r){r.refs++;r.comm+=1500;}}return up;});sendWelcomeEmail(em,nm);return null;
  },[users]);
  const upU=useCallback((id,upd)=>{
    setUsers(p=>p.map(u=>u.id===id?{...u,...upd}:u));if(user?.id===id)setUser(p=>({...p,...upd}));
    if(hasSupabase()){const p={};Object.entries(upd).forEach(([k,v])=>{const col=k==="affCode"?"aff_code":k;if(["ok","perms","fd","refs","comm","name","region","aff_code"].includes(col))p[col]=v;});if(Object.keys(p).length)supabase.from("profiles").update(p).eq("id",id).then(()=>{});}
  },[user?.id]);
  const lo=useCallback(()=>{if(hasSupabase())supabase.auth.signOut();setUser(null);nav("landing");},[nav]);
  const ctx={user,nav,login,register,lo,users,upU};
  if(page==="landing")return<><style>{CSS}</style><Landing {...ctx}/></>;
  if(page==="login"||page==="register")return<><style>{CSS}</style><Auth {...ctx} mode={page}/></>;
  if(page==="member")return<><style>{CSS}</style><MemberApp {...ctx}/></>;
  if(page==="admin")return<><style>{CSS}</style><AdminApp {...ctx}/></>;
  return<><style>{CSS}</style><Landing {...ctx}/></>;
}

/* AUTH */
function Auth({login:dl,register:dr,nav,mode}){
  const[isL,setIsL]=useState(mode==="login");const[em,setEm]=useState("");const[pw,setPw]=useState("");const[nm,setNm]=useState("");const[rg,setRg]=useState("tokyo");const[ref,setRef]=useState("");const[err,setErr]=useState("");const[ok,setOk]=useState("");
  useEffect(()=>{const p=new URLSearchParams(window.location.search);if(p.get("ref"))setRef(p.get("ref"));},[]);
  const sub=async e=>{e.preventDefault();setErr("");setOk("");if(isL){const r=await dl(em,pw);if(r)setErr(r);}else{if(!nm.trim())return setErr("\u540d\u524d\u5fc5\u9808");if(pw.length<6)return setErr("PW6\u6587\u5b57\u4ee5\u4e0a");const r=await dr(em,pw,nm,rg,ref);if(r)setErr(r);else setOk("\u767b\u9332\u5b8c\u4e86\uff01\u7ba1\u7406\u8005\u627f\u8a8d\u3092\u304a\u5f85\u3061\u304f\u3060\u3055\u3044\u3002");}};
  const inp={width:"100%",padding:"10px 12px",fontSize:13,border:`1px solid ${V.bd}`,borderRadius:6,outline:"none",fontFamily:"inherit"};
  return(<div style={{minHeight:"100vh",background:`linear-gradient(135deg,${V.bg},#dde3ea)`,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
    <div style={{background:"#fff",borderRadius:14,padding:"32px 30px",width:"100%",maxWidth:380,boxShadow:"0 4px 24px rgba(0,0,0,.04)"}}>
      <div onClick={()=>nav("landing")} style={{cursor:"pointer",display:"flex",alignItems:"center",gap:8,marginBottom:24}}><div style={{width:28,height:28,borderRadius:6,background:`linear-gradient(135deg,${V.pr},#2563eb)`,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:900,fontSize:13,fontFamily:"'Shippori Mincho',serif"}}>{"\u9769"}</div><span style={{fontSize:13,fontWeight:700}}>{"\u7d4c\u55b6\u9769\u65b0 AI \u30a2\u30b7\u30b9\u30c8"}</span></div>
      <h2 style={{fontSize:18,fontWeight:800,marginBottom:18}}>{isL?"\u30ed\u30b0\u30a4\u30f3":"\u4f1a\u54e1\u767b\u9332"}</h2>
      <form onSubmit={sub} style={{display:"flex",flexDirection:"column",gap:10}}>
        {!isL&&<><input value={nm} onChange={e=>setNm(e.target.value)} placeholder={"\u4f01\u696d\u540d"} style={inp}/><div style={{display:"flex",gap:5}}>{Object.entries(RG).map(([k,r])=><button key={k} type="button" onClick={()=>setRg(k)} style={{flex:1,padding:"8px 0",fontSize:12,fontWeight:rg===k?700:500,border:rg===k?"none":`1px solid ${V.bd}`,borderRadius:5,cursor:"pointer",background:rg===k?r.color:"#fff",color:rg===k?"#fff":V.mt}}>{r.short}</button>)}</div></>}
        <input type="email" value={em} onChange={e=>setEm(e.target.value)} placeholder={"\u30e1\u30fc\u30eb\u30a2\u30c9\u30ec\u30b9"} style={inp}/>
        <input type="password" value={pw} onChange={e=>setPw(e.target.value)} placeholder={"\u30d1\u30b9\u30ef\u30fc\u30c9"} style={inp}/>
        {!isL&&<input value={ref} onChange={e=>setRef(e.target.value)} placeholder={"\u7d39\u4ecb\u30b3\u30fc\u30c9\uff08\u4efb\u610f\uff09"} style={inp}/>}
        {err&&<div style={{background:"#fef2f2",border:"1px solid #fecaca",borderRadius:5,padding:8,fontSize:11,color:"#dc2626"}}>{err}</div>}
        {ok&&<div style={{background:"#f0fdf4",border:"1px solid #bbf7d0",borderRadius:5,padding:8,fontSize:11,color:"#16a34a"}}>{ok}</div>}
        <button type="submit" style={{background:`linear-gradient(135deg,${V.pr},#2563eb)`,border:"none",padding:11,fontSize:13,fontWeight:700,color:"#fff",cursor:"pointer",borderRadius:6}}>{isL?"\u30ed\u30b0\u30a4\u30f3":"\u767b\u9332\u3059\u308b"}</button>
      </form>
      <div style={{marginTop:12,textAlign:"center"}}><button onClick={()=>{setIsL(!isL);setErr("");setOk("");}} style={{background:"none",border:"none",fontSize:11,color:"#2563eb",cursor:"pointer"}}>{isL?"\u65b0\u898f\u767b\u9332":"\u30ed\u30b0\u30a4\u30f3"}{"\u306f\u3053\u3061\u3089"}</button></div>
      {isL&&<div style={{marginTop:12,padding:10,background:V.bg,borderRadius:5,fontSize:10,color:V.mt}}><b>{"\u7ba1\u7406\u8005:"}</b> admin@keikaku.jp / admin123<br/><b>{"\u4f1a\u54e1:"}</b> demo@example.com / demo123</div>}
    </div>
  </div>);
}

